local _, STBS = ...
function STBS:DiagnosticReport()
  local db=self:InitializeDatabase();local build,interface=self:GetBuild();local readable,writable,unavailable,hardware=0,0,0,0;for _,s in ipairs(self.Registry) do local v=self:ReadSetting(s);if v then readable=readable+1 else unavailable=unavailable+1 end;local can=self:CanUseCVar(s.key);if can then writable=writable+1 end;if s.hardwareDependent then hardware=hardware+1 end end
  local raid=C_CVar and C_CVar.GetCVar and C_CVar.GetCVar("RAIDsettingsEnabled") or "unknown";local mismatch=(db.preferences.graphicsMode==self.GRAPHICS_MODE_SPLIT and raid~="1") or (db.preferences.graphicsMode==self.GRAPHICS_MODE_UNIFIED and raid~="0")
  return table.concat({"S-Tier Blizz Settings "..self.VERSION,"Client build: "..tostring(build),"Interface: "..tostring(interface),"Game flavor: Retail","Database schema: "..self.DB_SCHEMA,"Profile schema: "..self.PROFILE_SCHEMA,"Export format: STBS1","Selected graphics mode: "..tostring(db.preferences.graphicsMode or "unset"),"Blizzard raid profile: "..tostring(raid),"Graphics mode mismatch: "..tostring(mismatch),"Registry/readable/writable/unavailable: "..#self.Registry.."/"..readable.."/"..writable.."/"..unavailable,"Edit Mode: "..tostring(self:SupportsEditMode()),"Keybindings: opt-in disabled","Latest backup: "..tostring(db.backups[1] and db.backups[1].timestamp or "none")},"\n")
end
